  ('promotion-d0d1b9a2-moex-00163', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，行政院修正減列支出實現數 500,000 元改列歲出 保留數時，該機關應為之會計分錄為何？', '["借：預付款500,000，貸：經費支出500,000；借：歲出保留數500,000，貸：歲出保留數準 備500,000", "借：其他應收款500,000，貸：經費支出500,000", "借：其他應收款500,000，貸：經費支出500,000；借：歲出保留數500,000，貸：歲出保留數準 備500,000", "借：歲出保留數500,000，貸：歲出保留數準備500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00164', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依中央公共債務會計制度之規定，下列關於中央公共債務會計之敘述，何者正確？', '["中央公共債務分內債及外債", "會計業務之處理，依該制度規定辦理，其未規定者，依相關法令規定辦理", "會計年度之開始、終了及結束期間，依會計法規定辦理", "會計制度依會計法第17條規定訂定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00165', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報及中央政府普通公務單位會計制度之一致規定，下列敘述何者正確？', '["中央政府為興辦公共建設所舉借的公債利息，應予以資本化", "甲機關於110年7月21日購入設備並完成運送、安裝、驗收，隨即開始使用。甲機關於7月 30日始支付其應負擔之運費2萬元，支付時應借：業務支出2萬元，貸：公庫撥入數2萬元", "乙機關配合政策，於110年7月3日參與P公司現金增資，以1億元取得該公司增資後30%股 權。同年8月15日乙機關獲配P公司現金股利1.67億元時，應借：繳付公庫數1.67億元，貸： 採權益法之投資評價調整1.67億元", "丙機關經管礦場已開採10年，110年7月31日宣布發現新礦脈且具開採價值，同年1月至7 月已支付之探勘費用，無須轉列遞耗資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00166', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '甲公務機關配合辦公大樓興建完成搬遷進駐，將原租用辦公廳舍辦理解約停租，並收回多年前支 付之押金，試依中央政府普通公務單位會計制度之一致規定，甲機關於收回押金繳庫時應為之完 整會計分錄？', '["借：存出保證金，貸：公庫撥入數", "借：公庫撥入數，貸：存出保證金", "借：繳付公庫數，貸：存出保證金", "借：資產負債淨額，貸：存出保證金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
